function solve(nums: number[]): number {
    const N = nums.length;
    if (N === 0) return 0;

    // Step 1: Preprocessing - Store all indices for each value.
    const valueIndices = new Map<number, number[]>();
    for (let i = 0; i < N; i++) {
        const val = nums[i];
        if (!valueIndices.has(val)) {
