            const R_k = L_prev - 1; 

            // Number of subarrays in this segment
            const S = R_k - L_k + 1;

            // Check if O_k exists in nums[L_k .. j]
            let isGood = false;
            const indices = valueIndices.get(O_k);

            if (indices) {
                // Find the smallest index p in indices such that p >= L_k
                const firstIndexGE_L = lowerBound(indices, L_k);

                // If such an index exists and it is <= j, then O_k is present in the subarray range [L_k, j]
