            valuePositions.set(val, []);
        }
        valuePositions.get(val)!.push(i);
    }

    let totalCount = 0;

    // Step 2: Iterate through all possible starting indices i
    for (let i = 0; i < N; i++) {
        let currentOR = 0;
        let k = i;

        // Iterate through segments where the OR value remains constant, starting from i
