            // Calculate the new OR value O_new = OR(nums[i..k])
            const O_new = currentOR | nums[k];

            // 1. Find k_end: The end of the segment having OR value O_new.
            let k_end = k;
            // Check if adding the next element maintains the current OR value O_new
            while (k_end + 1 < N) {
                const nextOR = O_new | nums[k_end + 1];
